package com.taskflow.repository;

import com.taskflow.entity.User;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

@DataJpaTest
@DisplayName("UserRepository")
class UserRepositoryTest {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TestEntityManager entityManager;

    private User savedUser;

    @BeforeEach
    void setUp() {
        User user = new User();
        user.setUsername("testuser");
        user.setPassword("hashedpassword123");
        user.setDisplayName("Test User");
        savedUser = entityManager.persistAndFlush(user);
    }

    // --- Red/Green Tests ---

    @Test
    @DisplayName("should find user by username when user exists")
    void shouldFindUserByUsernameWhenUserExists() {
        Optional<User> found = userRepository.findByUsername("testuser");

        assertThat(found).isPresent();
        assertThat(found.get().getUsername()).isEqualTo("testuser");
        assertThat(found.get().getDisplayName()).isEqualTo("Test User");
    }

    @Test
    @DisplayName("should return empty when username does not exist")
    void shouldReturnEmptyWhenUsernameDoesNotExist() {
        Optional<User> found = userRepository.findByUsername("nonexistent");

        assertThat(found).isEmpty();
    }

    @Test
    @DisplayName("should auto-generate id on persist")
    void shouldAutoGenerateIdOnPersist() {
        assertThat(savedUser.getId()).isNotNull();
        assertThat(savedUser.getId()).isGreaterThan(0L);
    }

    @Test
    @DisplayName("should set createdAt automatically on persist")
    void shouldSetCreatedAtAutomaticallyOnPersist() {
        assertThat(savedUser.getCreatedAt()).isNotNull();
    }

    // --- Boundary Tests ---

    @Test
    @DisplayName("should enforce username uniqueness constraint")
    void shouldEnforceUsernameUniquenessConstraint() {
        User duplicate = new User();
        duplicate.setUsername("testuser");
        duplicate.setPassword("anotherpassword");
        duplicate.setDisplayName("Another User");

        assertThatThrownBy(() -> {
            entityManager.persistAndFlush(duplicate);
        }).isInstanceOf(Exception.class);
    }

    @Test
    @DisplayName("should persist user with minimum length username (3 chars)")
    void shouldPersistUserWithMinimumLengthUsername() {
        User user = new User();
        user.setUsername("abc");
        user.setPassword("password123");
        user.setDisplayName("A");

        User persisted = entityManager.persistAndFlush(user);
        assertThat(persisted.getId()).isNotNull();
    }

    @Test
    @DisplayName("should persist user with maximum length username (50 chars)")
    void shouldPersistUserWithMaximumLengthUsername() {
        User user = new User();
        user.setUsername("a".repeat(50));
        user.setPassword("password123");
        user.setDisplayName("Max Username User");

        User persisted = entityManager.persistAndFlush(user);
        assertThat(persisted.getId()).isNotNull();
    }

    @Test
    @DisplayName("should persist user with maximum length displayName (100 chars)")
    void shouldPersistUserWithMaximumLengthDisplayName() {
        User user = new User();
        user.setUsername("maxdisplay");
        user.setPassword("password123");
        user.setDisplayName("D".repeat(100));

        User persisted = entityManager.persistAndFlush(user);
        assertThat(persisted.getDisplayName()).hasSize(100);
    }

    // --- findByUsername case sensitivity ---

    @Test
    @DisplayName("should not find user when username case differs")
    void shouldNotFindUserWhenUsernameCaseDiffers() {
        Optional<User> found = userRepository.findByUsername("TestUser");
        assertThat(found).isEmpty();
    }
}

